/**
 * Canvas renderer for the chess board
 * Handles all drawing operations for the game
 */

class Renderer {
    constructor(canvas, board) {
        this.canvas = canvas;
        this.ctx = canvas.getContext('2d');
        this.board = board;
        this.squareSize = canvas.width / 8;
        this.selectedSquare = null;
        this.validMoves = [];
        this.lastMove = null;
        this.animationManager = new AnimationManager();
        this.checkAnimation = null;
        this.gameOverAnimation = null;
        this.hoveredSquare = null;
    }

    /**
     * Render the entire board
     */
    render() {
        this.clearCanvas();
        this.drawBoard();
        this.drawHighlights();
        this.drawPieces();
        this.drawAnimations();
        this.drawDecorations();
    }

    /**
     * Clear the canvas
     */
    clearCanvas() {
        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    }

    /**
     * Draw the board squares
     */
    drawBoard() {
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const x = col * this.squareSize;
                const y = row * this.squareSize;
                const isDark = (row + col) % 2 === 1;

                if (isDark) {
                    GoTTheme.patterns.darkSquare(this.ctx, x, y, this.squareSize);
                } else {
                    GoTTheme.patterns.lightSquare(this.ctx, x, y, this.squareSize);
                }
            }
        }
    }

    /**
     * Draw highlights (selected, valid moves, check, etc.)
     */
    drawHighlights() {
        // Highlight last move
        if (this.lastMove) {
            GoTTheme.drawHighlight(
                this.ctx,
                this.lastMove.from.col * this.squareSize,
                this.lastMove.from.row * this.squareSize,
                this.squareSize,
                'lastMove'
            );
            GoTTheme.drawHighlight(
                this.ctx,
                this.lastMove.to.col * this.squareSize,
                this.lastMove.to.row * this.squareSize,
                this.squareSize,
                'lastMove'
            );
        }

        // Highlight selected square
        if (this.selectedSquare) {
            GoTTheme.drawHighlight(
                this.ctx,
                this.selectedSquare.col * this.squareSize,
                this.selectedSquare.row * this.squareSize,
                this.squareSize,
                'selected'
            );
        }

        // Draw valid move indicators
        for (const move of this.validMoves) {
            const x = move.col * this.squareSize;
            const y = move.row * this.squareSize;

            const targetPiece = this.board.getPieceAt(move.row, move.col);
            const isCapture = targetPiece !== null || move.isEnPassant;

            GoTTheme.drawMoveIndicator(this.ctx, x, y, this.squareSize, isCapture);
        }

        // Highlight king if in check
        const gameState = Rules.getGameState(this.board, this.board.currentTurn || 'white');
        if (gameState.inCheck) {
            const kingPos = this.board.findKing(this.board.currentTurn || 'white');
            if (kingPos) {
                GoTTheme.drawHighlight(
                    this.ctx,
                    kingPos.col * this.squareSize,
                    kingPos.row * this.squareSize,
                    this.squareSize,
                    'check'
                );

                // Draw check alert glow
                if (this.checkAnimation) {
                    this.checkAnimation.drawGlow(
                        this.ctx,
                        kingPos.col * this.squareSize,
                        kingPos.row * this.squareSize,
                        this.squareSize
                    );
                }
            }
        }
    }

    /**
     * Draw all pieces on the board
     */
    drawPieces() {
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const piece = this.board.getPieceAt(row, col);
                if (piece) {
                    // Skip if this piece is being animated
                    const isAnimating = this.animationManager.animations.some(
                        anim => anim.piece === piece && !anim.isComplete
                    );
                    if (isAnimating) continue;

                    const x = col * this.squareSize;
                    const y = row * this.squareSize;

                    // Draw hover effect
                    if (this.hoveredSquare &&
                        this.hoveredSquare.row === row &&
                        this.hoveredSquare.col === col) {
                        this.ctx.save();
